import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Cài Đặt Mod","description":"Bộ hướng dẫn từng bước để cài đặt mod cho Fabric.","frontmatter":{"title":"Cài Đặt Mod","description":"Bộ hướng dẫn từng bước để cài đặt mod cho Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"1.21.8/translated/vi_vn/players/installing-mods.md","filePath":"versions/1.21.8/translated/vi_vn/players/installing-mods.md","lastUpdated":1760721669000}`);var s={name:`1.21.8/translated/vi_vn/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Cài Đặt Mod <a class="header-anchor" href="#h1" aria-label="Permalink to “Cài Đặt Mod”">​</a></h1><p>Bài hướng dẫn này sẽ giúp bạn cài đặt các bản mod Fabric cho trình Launcher Minecraft chính thức.</p><p>Đối với các trình launcher bên thứ ba, bạn nên tham khảo tài liệu của họ.</p><h2 id="_1-tai-mod" tabindex="-1">1. Tải Mod <a class="header-anchor" href="#_1-tai-mod" aria-label="Permalink to “1. Tải Mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Bạn chỉ nên tải mod từ các nguồn uy tín. Để biết thêm thông tin về cách tìm mod, hãy tham khảo tài liệu <a href="./finding-mods">Tìm Mod</a>.</p></div><p>Phần lớn các bản mod đều yêu cầu Fabric API, thứ mà có thể được tải từ <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> hoặc <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a></p><p>Khi chuẩn bị tải mod, cần lưu ý:</p><ul><li>Chúng phải hỗ trợ phiên bản Minecraft bạn muốn chơi. Ví dụ một bản mod mà hoạt động tốt ở bản 1.20, có thể không hoạt động được ở bản 1.20.2.</li><li>Chúng phải dùng được cho Fabric và không phải là các trình mod khác.</li><li>Thêm vào đó, chúng phải đúng phiên bản Minecraft (Phiên bản Java).</li></ul><h2 id="_2-di-chuyen-tep-mod-vao-trong-thu-muc-mods" tabindex="-1">2. Di chuyển tệp mod vào trong thư mục <code>mods</code> <a class="header-anchor" href="#_2-di-chuyen-tep-mod-vao-trong-thu-muc-mods" aria-label="Permalink to “2. Di chuyển tệp mod vào trong thư mục mods”">​</a></h2><p>Thư mục mods có thể được tìm thấy ở các địa chỉ bên dưới ứng với mỗi hệ điều hành.</p><p>Bạn có thể dán những đường dẫn đó vào thanh địa chỉ của explorer để nhanh chóng điều hướng đến thư mục.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Khi bạn đã tìm thấy thư mục <code>mods</code>, bạn có thể di chuyển tệp mod <code>.jar</code> vào trong đó.</p><p><img src="/assets/players/installing-mods.png" alt="Cài đặt mod ở thư mục mods" loading="lazy"></p><h2 id="_3-ban-đa-hoan-tat" tabindex="-1">3. Bạn đã hoàn tất! <a class="header-anchor" href="#_3-ban-đa-hoan-tat" aria-label="Permalink to “3. Bạn đã hoàn tất!”">​</a></h2><p>Sau khi bạn đã di chuyển tệp mod vào trong thư mục <code>mods</code>, bạn có thể mở trình Launcher Minecraft và chọn hồ sơ Fabric từ danh sách thả xuống ở góc trái bên dưới và bấm nút chơi!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Trình Launcher Minecraft với hồ sơ Fabric được chọn" loading="lazy"></p><h2 id="khac-phuc-su-co" tabindex="-1">Khắc Phục Sự Cố <a class="header-anchor" href="#khac-phuc-su-co" aria-label="Permalink to “Khắc Phục Sự Cố”">​</a></h2><p>Nếu bạn gặp bất cứ vấn đề nào khi đang làm theo bài hướng dẫn này, bạn có thể xin sự trợ giúp từ kênh <code>#player-support</code> trong <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord Fabric</a>.</p><p>Bạn cũng có thể tự sửa chữa lỗi bằng cách tham khảo các trang khắc phục sự cố sau:</p><ul><li><a href="./troubleshooting/crash-reports">Báo Cáo Dừng Đột Ngột</a></li><li><a href="./troubleshooting/uploading-logs">Tải Lên Tệp Log</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};